E2Helper.Descriptions["addClip(e:vvn)"]    = "Adds a physical clip to the entity, cutting away everything on the far side of the plane through vector1 (origin) facing vector2 (normal). number1 is seal (default 1). Returns the new clip's ID, or 0 if it failed. The entity's mass is always preserved."
E2Helper.Descriptions["addClip(e:vv)"]     = "Alias of addClip(e:vvn) with seal defaulted to 1"
E2Helper.Descriptions["removeClips(e:)"]   = "Removes all clips on the entity"
E2Helper.Descriptions["removeClip(e:)"]    = "Alias of removeClips(e:); removes all clips on the entity"
E2Helper.Descriptions["removeClip(e:n)"]   = "Removes the clip on the entity with the given ID"
E2Helper.Descriptions["removeClipByID(e:n)"] = "Alias of removeClip(e:n); removes the clip on the entity with the given ID"
E2Helper.Descriptions["clipsLeft(e:)"]     = "Returns how many more clips can be added to the entity"
E2Helper.Descriptions["isClipped(e:)"]     = "Returns 1 if the entity currently has any clips, 0 otherwise"
E2Helper.Descriptions["getClips(e:)"]      = "Returns the entity's clips as an 'array' (table with numbers for keys) of tables, each with id, normal, distance and seal. Empty if the entity has no clips."
